#include <vector>
#include <numeric>
#include <algorithm>
using namespace std;

class Solution {
public:
    long long minProcessTime(vector<int>& goodProceeTime, int optimize) {
        int n = (int)goodProceeTime.size();
        long long total = 0;
        int maxValue = 0;
        for (int x : goodProceeTime) {
            total += x;
            maxValue = max(maxValue, x);
        }
        if (optimize <= 0 || total == 0) return total;

        // 按高度分组
        vector<vector<int>> byHeight(maxValue + 1);
        for (int i = 0; i < n; ++i) {
            if (goodProceeTime[i] > 0) byHeight[goodProceeTime[i]].push_back(i);
        }

        // 并查集初始化
        vector<int> parent(n), sz(n, 1), startHeight(n, 0);
        vector<char> active(n, 0);
        vector<long long> countByLen(n + 1, 0);

        auto findRoot = [&](int x) {
            int r = x;
            while (parent[r] != r) r = parent[r];
            while (parent[x] != x) {
                int p = parent[x];
                parent[x] = r;
                x = p;
            }
            return r;
        };

        // 结算连续段在高度变化间隔内的收益贡献
        auto closeComponent = [&](int root, int h) {
            long long times = (long long)startHeight[root] - h;
            if (times > 0) countByLen[sz[root]] += times;
        };

        // 合并两个连续段
        auto mergeComponent = [&](int a, int b, int h) {
            int ra = findRoot(a), rb = findRoot(b);
            if (ra == rb) return ra;
            closeComponent(ra, h);
            closeComponent(rb, h);
            if (sz[ra] < sz[rb]) swap(ra, rb);
            parent[rb] = ra;
            sz[ra] += sz[rb];
            startHeight[ra] = h;
            return ra;
        };

        // 从高到低逐层激活
        for (int h = maxValue; h >= 1; --h) {
            for (int idx : byHeight[h]) {
                active[idx] = 1;
                parent[idx] = idx;
                sz[idx] = 1;
                startHeight[idx] = h;
                int root = idx;
                if (idx > 0 && active[idx - 1]) root = mergeComponent(root, idx - 1, h);
                if (idx + 1 < n && active[idx + 1]) root = mergeComponent(root, idx + 1, h);
            }
        }

        // 收尾
        for (int i = 0; i < n; ++i) {
            if (active[i] && findRoot(i) == i) closeComponent(i, 0);
        }

        // 选取最大收益的段
        long long saved = 0;
        long long left = optimize;
        for (int len = n; len >= 1 && left > 0; --len) {
            long long take = min(left, countByLen[len]);
            saved += take * len;
            left -= take;
        }
        return total - saved;
    }
};
