var minProcessTime = function(goodProceeTime, optimize) {
    const n = goodProceeTime.length;
    let total = goodProceeTime.reduce((a, b) => a + b, 0);
    let maxVal = Math.max(...goodProceeTime);
    if (optimize <= 0 || total === 0) return total;

    // 按高度分组
    const byHeight = new Array(maxVal + 1);
    for (let i = 0; i <= maxVal; i++) byHeight[i] = [];
    for (let i = 0; i < n; i++) {
        if (goodProceeTime[i] > 0) byHeight[goodProceeTime[i]].push(i);
    }

    // 并查集初始化
    const parent = new Array(n);
    const size = new Array(n);
    const startHeight = new Array(n);
    const active = new Array(n).fill(false);
    const countByLen = new Array(n + 1).fill(0);

    function find(x) {
        while (parent[x] !== x) {
            parent[x] = parent[parent[x]];
            x = parent[x];
        }
        return x;
    }

    // 结算连续段在高度变化间隔内的收益贡献
    function closeComponent(root, h) {
        const times = startHeight[root] - h;
        if (times > 0) {
            countByLen[size[root]] += times;
        }
    }

    // 合并两个连续段
    function merge(a, b, h) {
        let ra = find(a), rb = find(b);
        if (ra === rb) return ra;
        closeComponent(ra, h);
        closeComponent(rb, h);
        if (size[ra] < size[rb]) [ra, rb] = [rb, ra];
        parent[rb] = ra;
        size[ra] += size[rb];
        startHeight[ra] = h;
        return ra;
    }

    // 从高到低遍历
    for (let h = maxVal; h >= 1; h--) {
        for (const idx of byHeight[h]) {
            active[idx] = true;
            parent[idx] = idx;
            size[idx] = 1;
            startHeight[idx] = h;
            let root = idx;
            if (idx > 0 && active[idx - 1]) root = merge(root, idx - 1, h);
            if (idx + 1 < n && active[idx + 1]) root = merge(root, idx + 1, h);
        }
    }

    // 收尾
    for (let i = 0; i < n; i++) {
        if (active[i] && find(i) === i) closeComponent(i, 0);
    }

    // 选取最大收益的段
    let saved = 0;
    let left = optimize;
    for (let len = n; len >= 1 && left > 0; len--) {
        const take = Math.min(left, countByLen[len]);
        saved += take * len;
        left -= take;
    }

    return total - saved;
};
